/*
CREATE TABLE [dbo].[OpUpd20211014](
	[Base_ID] [nvarchar](50) NULL,
	[Part_ID] [nvarchar](50) NULL,
	[SEQUENCE_NO] [nvarchar](5) NULL,
	[RESOURCE_ID] [nvarchar](50) NULL,
	[OP_TYPE] [nvarchar](50) NULL
) ON [PRIMARY]
GO
*/

SELECT * 
FROM LIVESupplemental.dbo.OpUpd20211014 U
LEFT OUTER JOIN LIVE.dbo.OPERATION O
ON O.WORKORDER_BASE_ID = U.Base_ID
AND O.WORKORDER_LOT_ID = '0'
AND O.WORKORDER_SPLIT_ID = '0'
AND O.WORKORDER_SUB_ID = '0'
AND O.WORKORDER_TYPE = 'M'
AND O.SEQUENCE_NO = U.SEQUENCE_NO
AND O.RESOURCE_ID = U.RESOURCE_ID
AND O.OPERATION_TYPE = U.OP_TYPE
WHERE O.WORKORDER_BASE_ID IS NULL
--> 80 ROWS, 5 NO MATCHES

SELECT O.WORKORDER_BASE_ID
, O.WORKORDER_LOT_ID
, O.WORKORDER_SPLIT_ID
, O.WORKORDER_SUB_ID
, O.WORKORDER_TYPE
, O.SEQUENCE_NO
, O.RESOURCE_ID
, O.OPERATION_TYPE
INTO #T1
FROM LIVESupplemental.dbo.OpUpd20211014 U
INNER JOIN LIVE.dbo.OPERATION O
ON O.WORKORDER_BASE_ID = U.Base_ID
AND O.WORKORDER_LOT_ID = '0'
AND O.WORKORDER_SPLIT_ID = '0'
AND O.WORKORDER_SUB_ID = '0'
AND O.WORKORDER_TYPE = 'M'
AND O.SEQUENCE_NO = U.SEQUENCE_NO
AND O.RESOURCE_ID = U.RESOURCE_ID
AND O.OPERATION_TYPE = U.OP_TYPE
--> 75 ROWS MATCHES

SELECT * 
FROM LIVE.dbo.USER_DEF_FIELDS UDF
WHERE ID IN ('UDF-0000074', 'UDF-0000075', 'UDF-0000076', 'UDF-0000077', 'UDF-0000078', 'UDF-0000079', 'UDF-0000080', 'UDF-0000081')

SELECT * FROM #T1

SELECT * 
FROM #T1 T
LEFT OUTER JOIN LIVE.dbo.USER_DEF_FIELDS UDF
ON UDF.PROGRAM_ID = 'VMMFGWIN_OP'
AND UDF.DOCUMENT_ID = CONVERT(NVARCHAR(MAX),T.WORKORDER_TYPE) + N'~' + T.WORKORDER_BASE_ID + N'~' + T.WORKORDER_LOT_ID + N'~' + T.WORKORDER_SPLIT_ID + N'~' + T.WORKORDER_SUB_ID + N'~' + CONVERT(NVARCHAR(MAX), T.SEQUENCE_NO)
AND ID IN ('UDF-0000074', 'UDF-0000075', 'UDF-0000076', 'UDF-0000077', 'UDF-0000078', 'UDF-0000079', 'UDF-0000080', 'UDF-0000081')
WHERE STRING_VAL IS NOT NULL
--> 14 ROWS WITH EXISTING VALUES; TEXT IS GOOD TO OVERWRITE

SELECT UDF.PROGRAM_ID
, UDF.ID
, UDF.DOCUMENT_ID
INTO #T2
FROM #T1 T
INNER JOIN LIVE.dbo.USER_DEF_FIELDS UDF
ON UDF.PROGRAM_ID = 'VMMFGWIN_OP'
AND UDF.DOCUMENT_ID = CONVERT(NVARCHAR(MAX),T.WORKORDER_TYPE) + N'~' + T.WORKORDER_BASE_ID + N'~' + T.WORKORDER_LOT_ID + N'~' + T.WORKORDER_SPLIT_ID + N'~' + T.WORKORDER_SUB_ID + N'~' + CONVERT(NVARCHAR(MAX), T.SEQUENCE_NO)
AND ID IN ('UDF-0000074', 'UDF-0000075', 'UDF-0000076', 'UDF-0000077', 'UDF-0000078', 'UDF-0000079', 'UDF-0000080', 'UDF-0000081')
--> 30 ROWS TO DELETE

SELECT * FROM #T2

/*
BEGIN TRANSACTION;
DELETE LIVE.dbo.USER_DEF_FIELDS 
FROM LIVE.dbo.USER_DEF_FIELDS UDF
INNER JOIN #T2 T
ON T.PROGRAM_ID = UDF.PROGRAM_ID
AND T.ID = UDF.ID
AND T.DOCUMENT_ID = UDF.DOCUMENT_ID
--> 30 ROWS DELETED
--> COMMIT TRANSACTION;
--> ROLLBACK TRANSACTION;

*/

SELECT UDF.PROGRAM_ID
, UDF.ID
, UDF.DOCUMENT_ID
FROM #T1 T
INNER JOIN LIVE.dbo.USER_DEF_FIELDS UDF
ON UDF.PROGRAM_ID = 'VMMFGWIN_OP'
AND UDF.DOCUMENT_ID = CONVERT(NVARCHAR(MAX),T.WORKORDER_TYPE) + N'~' + T.WORKORDER_BASE_ID + N'~' + T.WORKORDER_LOT_ID + N'~' + T.WORKORDER_SPLIT_ID + N'~' + T.WORKORDER_SUB_ID + N'~' + CONVERT(NVARCHAR(MAX), T.SEQUENCE_NO)
AND ID IN ('UDF-0000074', 'UDF-0000075', 'UDF-0000076', 'UDF-0000077', 'UDF-0000078', 'UDF-0000079', 'UDF-0000080', 'UDF-0000081')



